import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Save, Calendar, ShoppingBag, Hash, Receipt, CreditCard, User } from 'lucide-react';

const Lancamento = () => {
  const [cartoes, setCartoes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    descricao: '', 
    valor_total: '', 
    loja: '', 
    pedido: '', 
    nota_fiscal: '', 
    responsavel: '',
    parcelado: false, 
    num_parcelas: 1, 
    cartao: '', 
    data_compra: new Date().toISOString().split('T')[0]
  });

  // Busca os cartões cadastrados no banco
  useEffect(() => {
    fetchCartoes();
  }, []);

  async function fetchCartoes() {
    const { data, error } = await supabase
      .from('cartoes')
      .select('id, nome')
      .order('nome', { ascending: true });
    
    if (!error) setCartoes(data || []);
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    if (parseFloat(form.valor_total) <= 0) {
      alert("O valor deve ser maior que zero!");
      setLoading(false);
      return;
    }

    if (form.parcelado && !form.cartao) {
      alert("Por favor, selecione o cartão utilizado.");
      setLoading(false);
      return;
    }

    const { error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: form.parcelado ? parseInt(form.num_parcelas) : 1,
        cartao: form.parcelado ? form.cartao : 'À Vista'
      }]);

    if (error) {
      alert("Erro ao salvar: " + error.message);
    } else {
      alert("✅ Gasto registrado com sucesso!");
      // Reset funcional sem recarregar a página inteira
      setForm({
        descricao: '', valor_total: '', loja: '', pedido: '', 
        nota_fiscal: '', responsavel: '', parcelado: false, 
        num_parcelas: 1, cartao: '', data_compra: new Date().toISOString().split('T')[0]
      });
    }
    setLoading(false);
  };

  const labelStyle = { 
    display: 'flex', 
    alignItems: 'center', 
    gap: '8px', 
    fontSize: '0.75rem', 
    fontWeight: '700', 
    color: 'var(--text-muted)', 
    marginBottom: '8px',
    textTransform: 'uppercase'
  };

  // Estilo para o container do checkbox para igualar a altura do input (48px)
  const checkboxWrapperStyle = {
    height: '48px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: form.parcelado ? 'var(--primary-light)' : '#f8fafc',
    border: form.parcelado ? '1px solid var(--primary)' : '1px solid var(--border)',
    borderRadius: 'var(--radius)',
    cursor: 'pointer',
    transition: 'all 0.2s',
    gap: '8px'
  };

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '20px' }}>Novo Lançamento</h2>
      
      <div className="card">
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          
          {/* Linha 1: Data, Loja, Responsável */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
            <div className="input-group">
              <label style={labelStyle}><Calendar size={14} /> Data</label>
              <input type="date" className="form-control" value={form.data_compra} required onChange={e => setForm({...form, data_compra: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><ShoppingBag size={14} /> Loja</label>
              <input placeholder="Ex: Amazon" className="form-control" value={form.loja} onChange={e => setForm({...form, loja: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><User size={14} /> Responsável</label>
              <input placeholder="Quem comprou?" className="form-control" value={form.responsavel} onChange={e => setForm({...form, responsavel: e.target.value})} />
            </div>
          </div>

          {/* Linha 2: Descrição */}
          <div className="input-group">
            <label style={labelStyle}>Descrição</label>
            <input placeholder="O que você comprou?" className="form-control" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} />
          </div>

          {/* Linha 3: Pedido e NF */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'}}>
            <div className="input-group">
              <label style={labelStyle}><Hash size={14} /> Pedido</label>
              <input placeholder="Opcional" className="form-control" value={form.pedido} onChange={e => setForm({...form, pedido: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><Receipt size={14} /> Nota Fiscal</label>
              <input placeholder="Opcional" className="form-control" value={form.nota_fiscal} onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
            </div>
          </div>

          {/* Linha 4: Valor e Configurações de Pagamento (Grid Dinâmico) */}
          <div 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: form.parcelado ? '1fr 1fr 0.8fr 1.5fr' : '1fr 1fr', 
              gap: '15px', 
              alignItems: 'start' 
            }}
          >
            <div className="input-group">
              <label style={labelStyle}>Valor Total</label>
              <input 
                type="number" 
                step="0.01" 
                placeholder="0,00" 
                className="form-control" 
                required 
                value={form.valor_total}
                onChange={e => setForm({...form, valor_total: e.target.value})} 
              />
            </div>

            <div className="input-group">
              <label style={labelStyle}>Pagamento</label>
              <label style={checkboxWrapperStyle}>
                <input 
                  type="checkbox" 
                  checked={form.parcelado} 
                  onChange={e => setForm({...form, parcelado: e.target.checked})} 
                />
                <span style={{ fontWeight: '700', fontSize: '0.7rem', color: form.parcelado ? 'var(--primary)' : 'var(--text-muted)' }}>
                   {form.parcelado ? 'PARCELADO' : 'À VISTA'}
                </span>
              </label>
            </div>

            {form.parcelado && (
              <>
                <div className="input-group fade-in">
                  <label style={labelStyle}>Parcelas</label>
                  <input 
                    type="number" 
                    min="2" 
                    className="form-control" 
                    required 
                    value={form.num_parcelas}
                    onChange={e => setForm({...form, num_parcelas: e.target.value})} 
                    style={{ borderColor: 'var(--primary)', fontWeight: '700' }}
                  />
                </div>

                <div className="input-group fade-in">
                  <label style={labelStyle}><CreditCard size={14} /> Cartão</label>
                  <select 
                    className="form-control" 
                    required 
                    value={form.cartao}
                    onChange={e => setForm({...form, cartao: e.target.value})}
                    style={{ borderColor: 'var(--primary)', cursor: 'pointer' }}
                  >
                    <option value="">Selecione o cartão...</option>
                    {cartoes.map(c => (
                      <option key={c.id} value={c.nome}>{c.nome}</option>
                    ))}
                  </select>
                </div>
              </>
            )}
          </div>

          <button 
            type="submit" 
            className="btn-primary" 
            disabled={loading}
            style={{ height: '55px', marginTop: '10px', opacity: loading ? 0.7 : 1 }}
          >
            <Save size={20} style={{ marginRight: '10px' }} /> 
            {loading ? 'Salvando...' : 'Salvar Lançamento'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Lancamento;
